import React, { useState } from 'react';
import './Editvendor.css';

const Editvendor = ({ vendor, handleUpdate }) => {
    const [editedVendor, setEditedVendor] = useState({ ...vendor });

  const handleSubmit = (e) => {
    e.preventDefault();

    // Create an updatedvendor object with the modified fields
    const updatedVendor = {
      ...vendor,
      name,
      field,
      mail,
      tel,
      contactname
    };

    // Pass the updated vendor to the handleUpdate function
    handleUpdate(updatedVendor);
  };

  return (
    <div className="edit-vendor-container">
      <h2 className="edit-vendor-heading">Edit Vendor</h2>
      <form className="edit-vendor-form" onSubmit={handleSubmit}>
        <div className="form-row">
          <div className="form-group">
            <label htmlFor="name">Name:</label>
            <input
              type="text"
              id="name"
              value={name}
              onChange={(e) => setName(e.target.value)}
            />
          </div>
          <div className="form-group">
            <label htmlFor="description">Field:</label>
            <textarea
              id="field"
              value={field}
              onChange={(e) => setField(e.target.value)}
            />
          </div>
          <div className="form-group">
            <label htmlFor="mail">Mail:</label>
            <input
              type="email"
              id="mail"
              value={mail}
              onChange={(e) => setMail(e.target.value)}
            />
          </div>
          <div className="form-group">
            <label htmlFor="tel">Telephone:</label>
            <input
              type="tel"
              id="tel"
              value={tel}
              onChange={(e) => setTel(e.target.value)}
            />
          </div>
          <div className="form-group">
            <label htmlFor="contactname">Contact Name:</label>
            <input
              type="contactname"
              id="contactname"
              value={contactname}
              onChange={(e) => setContactname(e.target.value)}
            />
          </div>
          
        </div>
        <button type="submit" className="edit-vendor-btn">Update</button>
      </form>
    </div>
  );
};

export default Editvendor;
